@using sv_2a88d92533f7405aab3037830cf026da.Services
@inject NotificationService NotificationService
@implements IDisposable

<a class="nav-link notification-bell" href="notifications">
    <span class="bi bi-bell-fill-nav-menu" aria-hidden="true"></span>
    Notifications
    @if (NotificationService.UnreadCount > 0)
    {
        <span class="badge bg-danger rounded-pill ms-1">@NotificationService.UnreadCount</span>
    }
</a>

@code {
    protected override void OnInitialized()
    {
        NotificationService.OnChange += HandleStateChanged;
    }

    private void HandleStateChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        NotificationService.OnChange -= HandleStateChanged;
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using sv_2a88d92533f7405aab3037830cf026da.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h3>Notifications</h3>

<button class="btn btn-sm btn-outline-primary mb-3" @onclick="NotificationService.MarkAllRead"
        disabled="@(NotificationService.UnreadCount == 0)">
    Mark All Read
</button>

@if (!NotificationService.Notifications.Any())
{
    <p class="text-muted">No notifications.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Id</th>
                <th>Title</th>
                <th>Severity</th>
                <th>Status</th>
                <th>Timestamp</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in NotificationService.Notifications)
            {
                <tr class="@(item.IsRead ? "" : "fw-bold")">
                    <td>@item.Id</td>
                    <td>@item.Title</td>
                    <td>
                        <span class="badge @GetSeverityClass(item.Severity)">@item.Severity</span>
                    </td>
                    <td>@(item.IsRead ? "Read" : "Unread")</td>
                    <td>@item.Timestamp.ToString("g")</td>
                    <td>
                        @if (!item.IsRead)
                        {
                            <button class="btn btn-sm btn-outline-success me-1"
                                    @onclick="() => NotificationService.MarkAsRead(item.Id)">
                                Mark Read
                            </button>
                        }
                        <button class="btn btn-sm btn-outline-danger"
                                @onclick="() => NotificationService.Dismiss(item.Id)">
                            Dismiss
                        </button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    protected override void OnInitialized()
    {
        NotificationService.OnChange += HandleStateChanged;
    }

    private void HandleStateChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetSeverityClass(Severity severity) => severity switch
    {
        Severity.Info => "bg-info text-dark",
        Severity.Warning => "bg-warning text-dark",
        Severity.Critical => "bg-danger",
        _ => "bg-secondary"
    };

    public void Dispose()
    {
        NotificationService.OnChange -= HandleStateChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_2a88d92533f7405aab3037830cf026da.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h3>Dashboard</h3>

<div class="card mb-4" style="max-width: 600px;">
    <div class="card-header">
        <strong>Recent Unread Notifications</strong>
    </div>
    <div class="card-body">
        @{
            var recentUnread = NotificationService.GetRecentUnread(3).ToList();
        }
        @if (!recentUnread.Any())
        {
            <p class="text-muted mb-0">No unread notifications.</p>
        }
        else
        {
            <ul class="list-group list-group-flush">
                @foreach (var item in recentUnread)
                {
                    <li class="list-group-item d-flex justify-content-between align-items-center">
                        <span>
                            <span class="badge @GetSeverityClass(item.Severity) me-2">@item.Severity</span>
                            @item.Title
                        </span>
                        <button class="btn btn-sm btn-outline-danger"
                                @onclick="() => NotificationService.Dismiss(item.Id)">
                            Dismiss
                        </button>
                    </li>
                }
            </ul>
        }
    </div>
</div>

<p class="text-muted"><em>A new simulated notification arrives every 15 seconds while on this page.</em></p>

@code {
    private Timer? _timer;
    private int _simulationCounter;

    private static readonly string[] SimulatedTitles =
    [
        "CPU usage spike detected",
        "Deployment completed",
        "Disk space running low",
        "New user registered",
        "Payment failed",
        "Backup succeeded",
        "Service health check failed",
        "Certificate expiring soon"
    ];

    protected override void OnInitialized()
    {
        NotificationService.OnChange += HandleStateChanged;

        // Background timer: simulates incoming notifications every 15 seconds
        _timer = new Timer(SimulateNotification, null, TimeSpan.FromSeconds(15), TimeSpan.FromSeconds(15));
    }

    private void SimulateNotification(object? state)
    {
        var title = SimulatedTitles[_simulationCounter % SimulatedTitles.Length];
        var severity = (Severity)(_simulationCounter % 3);
        _simulationCounter++;

        InvokeAsync(() =>
        {
            NotificationService.Add(title, severity);
            StateHasChanged();
        });
    }

    private void HandleStateChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetSeverityClass(Severity severity) => severity switch
    {
        Severity.Info => "bg-info text-dark",
        Severity.Warning => "bg-warning text-dark",
        Severity.Critical => "bg-danger",
        _ => "bg-secondary"
    };

    public void Dispose()
    {
        _timer?.Dispose();
        NotificationService.OnChange -= HandleStateChanged;
    }
}

